  ('fd6c1fe3-0d45-5955-b716-a4d446107e1d', 'commercial', 'Potterycrafts', 'Earthenware Powder Glazes', 'P2135', 'Iron Glow Matte Powder Glaze', 'Cone 06 / Cone 04', 'Potterycrafts Iron Glow is a crystallite earthenware glaze that gives a stoneware effect at a low temperature.', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Iron-Glow-Matte-Powder-Glaze.jpg?v=1750925316', 'Matte', null, 'https://potterycrafts.co.uk/products/potterycrafts-iron-glow-matte-powder-glaze'),
  ('32ac4d36-4976-5371-9a8c-124def975421', 'commercial', 'Potterycrafts', 'Raku Glazes', 'P2590', 'Sky Blue Crackle Raku Powder Glaze', 'Raku', 'These glazes produce widely differing results depending on the type of body and thickness of application. Because of the aspect of finished product, they are not recommended for food ware.', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Sky-Blue-Crackle-Raku-Powder-Glaze.jpg?v=1750923810', 'Crackle, Raku', 'Blue', 'https://potterycrafts.co.uk/products/potterycrafts-sky-blue-crackle-raku-powder-glaze'),
  ('69d62391-3cee-596b-9573-8218aa2f9117', 'commercial', 'Potterycrafts', 'Earthenware Powder Glazes', 'P2039', 'Transparent Leadless High-Temp Powder Glaze', 'Cone 06 / Cone 04', 'Potterycrafts leadless transparent glossy glaze, for high fired earthenware. Firing temperature: 1120-1180°C. Non-toxic (lead-free).', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Transparent-Leadless-High-Temp-Powder-Glaze_33ee3de7-9f34-4f3f-bca4-5032d2bcd8bd.jpg?v=1721147982', 'Transparent, Glossy', 'Clear', 'https://potterycrafts.co.uk/products/potterycrafts-transparent-leadless-high-temp-powder-glaze'),
  ('53c05f06-2e42-5c80-bb05-9b28bc8f0d6b', 'commercial', 'Potterycrafts', 'Earthenware Powder Glazes', 'P2544', 'Tamba Brown Powder Glaze', 'Cone 06 / Cone 04', 'Different effects can be achieved with the Potterycrafts Tamba Brown Oxidising Powder Glaze. Variable thickness and different heating and cooling, especially on embossed ware. Temperature Range: 1220-1260°C. Gives brighter results when used on whiter firing bodies. Simple to apply for both beginners and advanced potters.', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Tamba-Brown-Powder-Glaze.jpg?v=1749120916', null, 'Brown', 'https://potterycrafts.co.uk/products/potterycrafts-tamba-brown-powder-glaze'),
  ('17381b57-4ab8-52ec-b16e-136456f7cc6d', 'commercial', 'Potterycrafts', 'Decorating Slips', 'P2317', 'Harry Stringer Green Powder Decorating Slip', 'Cone 06 / Cone 6 / Cone 10', 'Harry Stringer green decorating slip has been designed by Harry Horlock-Stringer of the Taggs Yard School of Ceramics to create effects similar to those that would be obtained from a flame fired reduction firing. Different thickness of slip and glaze, as well as a variation in firing temperature can produce remarkable effects in finished ware, such as obtaining blue, black, green and orange from the same slip application. Temperature Range: 1260-1280°C', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Harry-Stringer-Green-Powder-Decorating-Slip.jpg?v=1749120034', null, 'Green', 'https://potterycrafts.co.uk/products/potterycrafts-harry-stringer-green-powder-decorating-slip'),
  ('31f52e0c-89bb-57cf-a30a-b81ef1add2aa', 'commercial', 'Potterycrafts', 'Decorating Slips', 'P2318', 'Harry Stringer Blue Powder Decorating Slip', 'Cone 06 / Cone 6 / Cone 10', 'Harry Stringer blue decorating slip has been designed by Harry Horlock-Stringer of the Taggs Yard School of Ceramics to create effects similar to those that would be obtained from a flame fired reduction firing. Different thickness of slip and glaze, as well as a variation in firing temperature can produce remarkable effects in finished ware, such as obtaining blue, black, green and orange from the same slip application. Temperature Range: 1260-1280°C', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Harry-Stringer-Blue-Powder-Decorating-Slip.jpg?v=1749118324', null, 'Blue', 'https://potterycrafts.co.uk/products/potterycrafts-harry-stringer-blue-powder-decorating-slip'),
