  ('9be35c54-133c-5359-b0f8-0d7e15cb828a', 'commercial', 'Potterycrafts', 'Stoneware Powder Glazes', 'P2516', 'Derek Emms Copper Red Powder Glaze', 'Cone 6 / Cone 10', 'Potterycrafts Emms Copper Red glaze can be used in oxidising firing, but better colour and surface quality will be obtained in reduction firing. Reduce to 1000°C from 1280°C with a short period of oxidisation at the end of firing. Temperature Range: 1280-1300°C. Non-toxic (lead-free)– Perfect for tableware. Please follow manufacturer instructions. Simple to apply for both beginners and advanced potters.', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Derek-Emms-Copper-Red-Powder-Glaze_21c2e42d-cabc-4b3e-95ba-3fc669183bec.jpg?v=1722584804', null, 'Red', 'https://potterycrafts.co.uk/products/potterycrafts-derek-emms-copper-red-powder-glaze'),
  ('996bc3f5-c994-52a3-952f-3b1a3d71a6e5', 'commercial', 'Potterycrafts', 'Stoneware Powder Glazes', 'P2300', 'Taggs Yard Chun Tenmoku Powder Glaze', 'Cone 6 / Cone 10', 'Potterycrafts Taggs Yard Chun Tenmoku Powder Glaze has been designed by Harry Horlock-Stringer of the Taggs Yard School of Ceramics. This is a transparent glaze that when layer over P2302 reactive slip will create effects similar to those that would be obtained from a flame fired reduction firing. Different thickness of slip and glaze, as well as a variation in firing temperature can produce remarkable effects in finished ware, such as obtaining blue, black, green, and orange from the same slip application. Temperature Range: 1260-1280°C. Non-toxic (lead-free)– Perfect for tableware. Please follow manufacturer instructions. Simple to apply for both beginners and advanced potters. The image shown is P2300 Chun Tenmoku glaze layered over P2302 reactive slip.', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Taggs-Yard-Chun-Tenmoku-Powder-Glaze_d9b651da-8f7b-4b42-bd48-49fc9ebac541.jpg?v=1722584769', null, null, 'https://potterycrafts.co.uk/products/potterycrafts-taggs-yard-chun-tenmoku-powder-glaze'),
  ('07ab0d63-ad0d-59ae-9174-a1d8252ad0f4', 'commercial', 'Potterycrafts', 'Earthenware Powder Glazes', 'P2514', 'Derek Emms Chun Blue Ilmenite Speck Powder Glaze', 'Cone 06 / Cone 04', 'Potterycrafts Emms Chun Blue Ilmenite Speck glaze can be used in oxidising firing, but better colour and surface quality will be obtained in reduction firing. Reduce to 1000°C from 1280°C with a short period of oxidisation at the end of firing. Temperature Range: 1260-1280°C. Non-toxic (lead-free)– Perfect for tableware. Please follow manufacturer instructions. Simple to apply for both beginners and advanced potters.', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Derek-Emms-Chun-Blue-Ilmenite-Speck-Powder-Glaze.jpg?v=1729868243', null, 'Blue', 'https://potterycrafts.co.uk/products/potterycrafts-derek-emms-chun-blue-ilmenite-speck-powder-glaze'),
  ('b50bb323-fad4-5938-aca7-ddad7f30f0df', 'commercial', 'Potterycrafts', 'Stoneware Powder Glazes', 'P2310', 'Taggs Yard Stony White Gingery Powder Glaze', 'Cone 6 / Cone 10', 'Potterycrafts Taggs Yard Stony White Gingery has been designed by Harry Horlock-Stringer of the Taggs Yard School of Ceramics to create effects similar to those that would be obtained from a flame fired reduction firing. Different thickness of the glaze, as well as a variation in firing temperature can produce remarkable effects in finished ware, such as obtaining blue, black, green, and orange from the same application. Temperature Range: 1260-1280°C. Non-toxic (lead-free)– Perfect for tableware. Please follow manufacturer instructions. Simple to apply for both beginners and advanced potters.', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Taggs-Yard-Stony-White-Gingery-Powder-Glaze_7f722130-e2ae-4a2b-83d3-5bc91bd0bc34.jpg?v=1722584771', null, 'White', 'https://potterycrafts.co.uk/products/potterycrafts-taggs-yard-stony-white-gingery-powder-glaze'),
  ('db04f2cf-6ebb-5122-997e-f105920b9e0e', 'commercial', 'Potterycrafts', 'Earthenware Powder Glazes', 'P2312', 'Taggs Yard Celadon Powder Glaze', 'Cone 06 / Cone 04', 'Potterycrafts Taggs Celadon has been designed by Harry Horlock-Stringer of the Taggs Yard School of Ceramics to create effects similar to those that would be obtained from a flame fired reduction firing. Different thickness of slip and glaze, as well as a variation in firing temperature can produce remarkable effects in finished ware, such as obtaining blue, black, green, and orange from the same application. Temperature Range: 1260-1280°C. Non-toxic (lead-free)– Perfect for tableware. Please follow manufacturer instructions. Simple to apply for both beginners and advanced potters.', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Taggs-Yard-Celadon-Powder-Glaze_1bd1cf4d-7c96-4e83-b8ba-25f23052ea72.jpg?v=1722584773', null, 'Green', 'https://potterycrafts.co.uk/products/potterycrafts-taggs-yard-celadon-powder-glaze'),
  ('98105273-efd6-582e-b6f0-b7beb6656b4d', 'commercial', 'Potterycrafts', 'Stoneware Powder Glazes', 'P2510', 'Derek Emms Matt White Powder Glaze', 'Cone 6 / Cone 10', 'Potterycrafts Derek Emms Matt White glaze can be used in oxidising firing, but better colour and surface quality will be obtained in reduction firing. Reduce to 1000°C from 1280°C with a short period of oxidisation at the end of firing. Temperature Range: 1250-1280°C. Non-toxic (lead-free)– Perfect for tableware. Please follow manufacturer instructions. Simple to apply for both beginners and advanced potters.', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Derek-Emms-Matt-White-Powder-Glaze_bf8ecaab-4186-4ee1-8442-1f00a1ca59a6.jpg?v=1722584775', 'Matte', 'White', 'https://potterycrafts.co.uk/products/potterycrafts-derek-emms-matt-white-powder-glaze'),
  ('97161741-8bd8-5232-9dcd-b6ab6753b5d7', 'commercial', 'Potterycrafts', 'On-Glaze Colours', 'P4350', 'Green Yellow Leadfree Powder On-Glaze', 'Cone 018 / Cone 016', 'Potterycrafts Green Yellow is a lead-free powder glaze. Powdered colours can be used for China painting or screen printing depending on the chosen medium. Powders should be thoroughly mixed into a medium on a glass slab with a palette knife. The approximate ratio is 2-part colours to 1 part medium. Non-toxic (lead-free)– Perfect for tableware. Please follow manufacturer instructions. Temperature Range for earthenware, tile and bone China: 780-820°C. Temperature Range for porcelain: 800-840°C.', 'https://cdn.shopify.com/s/files/1/0865/4399/1066/files/Potterycrafts-Green-Yellow-Leadfree-Powder-On-Glaze_8853a446-9f17-4c5c-86c1-cd06894001cd.jpg?v=1727875844', null, 'Yellow, Green', 'https://potterycrafts.co.uk/products/potterycrafts-green-yellow-leadfree-powder-on-glaze'),
